  DECLARE
    v_study_key NUMBER;
    v_insurancefee_key NUMBER;
    v_order_control_id  VARCHAR2(32) := @ORDER_CONTROL_ID;
    v_scheduled_procedure_step VARCHAR2(32) := @SCHEDULED_PROC_STATUS;
    v_msps_key NUMBER;
  BEGIN
    v_study_key := sp_mapper.put_order(
                      @EVENT_TYPE, -- event_type
                      @ORDER_CONTROL_ID, -- order_control_id
                      @PATIENT_ID, -- patient_id
                      null, -- patient_id_issuer_code
                      @PATIENT_NAME, -- patient_name
                      null, -- last_name
                      null, -- first_name
                      null, -- middle_name
                      null, -- prefix
                      null, -- suffix
                      @PATIENT_BIRTH_DATE, -- patient_birth_dttm
                      @PATIENT_SEX, -- patient_sex
                      null, -- race_code
                      @CONFIDENTIALITY, -- confidentiality
                      null, -- account_no
                      null, -- address
                      @PATIENT_LOCATION, -- patient_location
                      @PATIENT_RESIDENCY, -- patient_residence
                      @REFER_DOCTOR, -- refer_doctor_id
                      @CONSULT_DOCTOR, -- consult_doctor_id
                      @PROC_PLACER_ORDER_NO, -- placer_order_id
                      @PROC_FILLER_ORDER_NO, -- filler_order_id
                      @ACCESSION_NO, -- accession_no
                      @SCHEDULED_PROC_STATUS, -- order_stat
                      @IMAGING_REQUEST_REASON, -- order_reason
                      @IMAGING_REQUEST_COMMENTS, -- order_comments
                      @IMAGING_REQUEST_DTTM, -- order_dttm
                      @REQUEST_DOCTOR, -- order_doctor_id
                      @REQUEST_DEPARTMENT, -- order_department
                      null, -- order_entry_user_id
                      null, -- order_entry_location
                      null, -- order_callback_phone_no
                      @ATTEND_DOCTOR, -- attend_doctor_id
                      @PERFORM_DOCTOR, -- perform_doctor_id
                      null, -- reqproc_stat
                      @REQUESTED_PROC_ID, -- reqproc_id
                      @REQUESTED_PROC_DESC, -- reqproc_desc
                      @REQUESTED_PROC_CODES, -- reqproc_code_value
                      null, -- reqproc_code_scheme
                      null, -- reqproc_code_version
                      null, -- reqproc_code_meaning
                      @STUDY_INSTANCE_UID, -- study_instance_uid
                      @REQUESTED_PROC_REASON, -- reqproc_reason
                      @REQUESTED_PROC_COMMENTS, -- reqproc_comments
                      @REQUESTED_PROC_PRIORITY, -- reqproc_priority
                      null, -- reqproc_location
                      null, -- patient_arrange
                      @DIAGNOSIS, -- diagnosis for ODBC
                      @OTHER_PATIENT_ID, -- other_patient_id for ODBC
                      @OTHER_PATIENT_NAME, -- other_patient_name for ODBC
                      'AE', -- source_aetitle
                      'BROKER', -- broker_aetitle
                      'ODBC' -- broker_type
                    );
    
    IF v_order_control_id = 'NW' AND v_scheduled_procedure_step IN ('120', '110', 'SC') THEN
      v_msps_key := sp_mapper.put_msps(
                      v_study_key, -- study_key
                      @REQUESTED_PROC_CODES, -- reqproc_code_value
                      null, -- reqproc_code_scheme
                      @SCHEDULED_PROC_ID, -- sps_id
                      @SCHEDULED_MODALITY, -- modality
                      @SCHEDULED_DTTM, -- sps_start_dttm
                      @SCHEDULED_PROC_ID, -- protcode_value
                      @SCHEDULED_ACTION_CODES, -- protcode_scheme
                      @SCHEDULED_PROC_DESC, -- protcode_meaning
                      1, -- index
                      'AE', -- aetitle
                      @SCHEDULED_LOCATION, -- scheduled_location
                      'ODBC', -- broker_type : 'HL7-PACS' = PACS Only, 'HL7-IHE' = RIS & PACS
                      @ORDER_CONTROL_ID, -- order_control_id
                      @SCHEDULED_PROC_STATUS -- order_stat
                    );
    END IF;
    
    /*
    v_insurancefee_key := sp_mapper.put_insurancefee(
                            @STUDY_INSTANCE_UID, -- study_instance_uid
                            @PATIENT_ID, -- patient_id
                            @PATIENT_BIRTH_DATE, -- patient_birth_dttm
                            @SCHEDULED_DTTM, -- request_dttm
                            @REQUESTED_PROC_ID, -- request_code
                            @REQUESTED_PROC_DESC, -- request_name
                            @ACCESSION_NO, -- accession_no
                            @INSURANCE_CODE, -- insurance_code
                            @SCHEDULED_MODALITY, -- modality
                            @EMERGENCY, -- emergency
                            @SPECIAL_DOCTOR, -- special_doctor
                          );
      */                     
  END;

      
        DECLARE
            v_study_key                     NUMBER;
            v_msps_key                      NUMBER;
            v_insurancefee_key              NUMBER;
            
            v_broker_aetitle                VARCHAR2(32)   := '';
            v_order_control_id              VARCHAR2(16)   := '';
            v_event_type                    VARCHAR2(32)   := @EVENT_TYPE;
            v_character_set                 VARCHAR2(32)   := @CHARACTER_SET;
