                    v_study_ssn,
                    v_insurance_code,           -- 60
                    v_emergency,
                    v_special_doctor,           -- 62
                    
                    v_m_patient_id_issuer,
                    v_m_last_name,
                    v_m_first_name,
                    v_m_middle_name,
                    v_m_prefix,
                    v_m_suffix,
                    v_m_race_code,
                    v_m_account_no,             -- 70
                    v_m_address,
                    v_m_order_entry_user_id, 
