                    v_m_req_proc_code_version,
                    v_m_req_proc_code_meaning,
                    v_m_req_proc_location,
                    v_m_patient_arrange,        -- 80
                    v_m_source_aetitle,
                    v_m_broker_type             -- 82
                );
            
            v_study_key := sp_mapper.put_order(
                    v_event_type,
                    v_order_control_id              ,
                    v_patient_id                    ,
                    v_m_patient_id_issuer           , -- v_patient_id_issuer_code
                    v_patient_name                  ,
