                    v_requested_proc_id             , -- v_reqproc_id
                    v_requested_proc_desc           , -- v_reqproc_desc
                    v_requested_proc_codes          , -- v_reqproc_code_value
                    v_m_req_proc_code_scheme        , -- v_reqproc_code_scheme
                    v_m_req_proc_code_version       , -- v_reqproc_code_version    -- 40
                    v_m_req_proc_code_meaning       , -- v_reqproc_code_meaning
                    v_study_instance_uid            ,
                    v_requested_proc_reason         , -- v_reqproc_reason
                    v_requested_proc_comments       , -- v_reqproc_comments
                    v_requested_proc_priority       , -- v_reqproc_priority
                    v_m_req_proc_location           , -- v_reqproc_location
                    v_m_patient_arrange             , -- v_patient_arrange
                    v_diagnosis                     ,
                    v_other_patient_id              ,
                    v_other_patient_name            , -- 50
                    v_m_source_aetitle              , -- v_source_aetitle
                    v_broker_aetitle                ,
                    v_m_broker_type                 , -- v_broker_type
                    v_study_ssn                     , -- v_patient_ssn
                    null                            , -- v_diagnosis_code
                    null                            , -- v_diagnosis_code_meaning
                    null                            , -- v_note_and_comments
                    null                            , -- v_sending_facility
                    v_patient_weight                ,
                    v_patient_size                  , -- 60
                    null                            , -- v_vet_sex_neutered
                    null                            , -- v_species_code_description
                    null                            , -- v_breed_code_description
                    null                            , -- v_nk1_name
                    null                            , -- v_nk1_relationship
                    null                            , -- v_nk1_organization_name
                    null                            , -- v_crosswalk_hl7request_key
                    null                              -- v_enable_orderphysicians -- 68
                );

            IF v_order_control_id = 'NW' AND v_scheduled_proc_status IN ('120', '110', 'SC') THEN
              v_msps_key := sp_mapper.put_msps(
                            v_study_key, -- study_key
                            v_requested_proc_codes, -- reqproc_code_value
                            v_m_req_proc_code_scheme, -- reqproc_code_scheme
                            v_scheduled_proc_id, -- sps_id
                            v_scheduled_modality, -- modality
                            v_scheduled_dttm, -- sps_start_dttm
                            v_scheduled_proc_id, -- protcode_value
                            v_scheduled_action_codes, -- protcode_scheme
                            v_scheduled_proc_desc, -- protcode_meaning
                            1, -- index
                            v_scheduled_aetitle, -- aetitle
                            v_scheduled_location, -- scheduled_location
                            v_m_broker_type, -- broker_type : 'HL7-PACS' = PACS Only, 'HL7-IHE' = RIS & PACS, 'ODBC' = ODBC
                            v_order_control_id, -- order_control_id
                            v_scheduled_proc_status -- order_stat
                          );
            END IF;
          
            /*
            v_insurancefee_key := sp_mapper.put_insurancefee(
                                  v_study_instance_uid,
                                  v_patient_id,
                                  v_patient_birth_dttm,
                                  v_scheduled_dttm, -- request_dttm
                                  v_requested_proc_id, -- request_code
                                  v_requested_proc_desc, -- request_name
                                  v_accession_no,
                                  v_insurance_code,
                                  v_scheduled_modality, -- modality
                                  v_emergency, -- emergency
                                  v_special_doctor -- special_doctor
                          );
            */
        END;


  DECLARE
    v_patient_key NUMBER;
  BEGIN
    v_patient_key := sp_mapper.put_patient(
                      @EVENT_TYPE, -- event_type
                      @PATIENT_ID, -- patient_id
                      null, -- prior_patient_id
                      null, -- patient_id_issuer_code
                      @PATIENT_SSN, -- patient_ssn
                      @PATIENT_NAME, -- patient_name
                      null, -- last_name
                      null, -- first_name
                      null, -- middle_name
                      null, -- prefix
                      null, -- suffix
                      null, -- marital_stat
                      null, -- confidentiality
                      @PATIENT_BIRTH_DTTM, -- patient_birth_dttm
                      null, -- patient_death_dttm
                      @PATIENT_SEX, -- patient_sex
                      @PATIENT_SIZE, -- patient_size
                      @PATIENT_WEIGHT, -- patient_weight
                      @BLOOD_TYPE, -- blood_type_abo
                      null, -- blood_type_rh
                      null, -- citizenship
                      null, -- occupation
                      null, -- race_code
                      null, -- language_code
                      null, -- religion_code
                      null, -- birthplace
                      null, -- multiple_birth_status
                      null, -- birth_order
                      @EMAIL, -- email
                      null, -- phone_no
                      null, -- pregnancy_code
                      null, -- patient_stat
                      null, -- account_no
                      null, -- contact_type
                      @TEL_NO, -- home_phone_no
                      null, -- busi_phone_no
                      @FAX_NO, -- fax_no
                      @ADDRESS, -- address
                      null, -- city
                      null, -- state
                      null, -- country
                      @ZIPCODE, -- zipcode
                      null, -- visit_number
                      null, -- visit_stat
                      @ADMIT_DTTM, -- admit_dttm
                      @DISCHARGE_DTTM, -- discharge_dttm
                      @CURRENT_LOCATION, -- patient_location
                      @CURRENT_RESIDENCY, -- patient_residence
                      @CURRENT_DOCTOR_ID, -- refer_doctor_id
                      null, -- consult_doctor_id
                      null, -- institution_code
                      null, -- visit_comment
                      null, -- admit_route
                      null, -- lastmen_strual_dttm
                      @PREGNANCY_STATUS, -- pregnancy_status
                      null, -- code_abbreviation
                      null, -- station_code
                      @ENGLISH_NAME, -- english_name
                      @ETHNIC_GROUP, -- ethnic_group
                      @CURRENT_DEPARTMENT, -- current_department
                      @CURRENT_DOCTOR_NAME, -- refer_doctor_name
                      null, -- consult_doctor_name
                      'BROKER', -- broker_aetitle
                      'ODBC' -- broker_type
                      );
  END;

      
        DECLARE
            v_patient_key                   NUMBER;

            v_broker_aetitle                VARCHAR2(32)   := '';
            v_event_type                    VARCHAR2(32)   := @EVENT_TYPE;
            v_patient_id                    VARCHAR2(64)   := @PATIENT_ID;
            v_patient_name                  VARCHAR2(64)   := @PATIENT_NAME;
            v_english_name                  VARCHAR2(32)   := @ENGLISH_NAME;
            v_patient_ssn                   VARCHAR2(32)   := @PATIENT_SSN;
            v_patient_birth_dttm            VARCHAR2(8)    := @PATIENT_BIRTH_DTTM;
            v_patient_sex                   VARCHAR2(8)    := @PATIENT_SEX;
            v_patient_weight                VARCHAR2(8)    := @PATIENT_WEIGHT;
            v_patient_size                  VARCHAR2(8)    := @PATIENT_SIZE; -- 10
            v_ethnic_group                  VARCHAR2(32)   := @ETHNIC_GROUP;
            v_tel_no                        VARCHAR2(32)   := @TEL_NO;
            v_fax_no                        VARCHAR2(32)   := @FAX_NO;
            v_zipcode                       VARCHAR2(16)   := @ZIPCODE;
            v_address                       VARCHAR2(128)  := @ADDRESS;
            v_email                         VARCHAR2(64)   := @EMAIL;
            v_blood_type                    VARCHAR2(8)    := @BLOOD_TYPE;
            v_pregnancy_status              VARCHAR2(8)    := @PREGNANCY_STATUS;
            v_current_location              VARCHAR2(32)   := @CURRENT_LOCATION;
            v_current_residency             VARCHAR2(32)   := @CURRENT_RESIDENCY; -- 20
            v_current_department            VARCHAR2(32)   := @CURRENT_DEPARTMENT;
            v_current_doctor_id             VARCHAR2(32)   := @CURRENT_DOCTOR_ID;
            v_current_doctor_name           VARCHAR2(64)   := @CURRENT_DOCTOR_NAME;
            v_admit_dttm                    VARCHAR2(14)   := @ADMIT_DTTM;
            v_discharge_dttm                VARCHAR2(14)   := @DISCHARGE_DTTM; -- 25
            
            v_p_prior_patient_id            VARCHAR2(64);
            v_p_patient_id_issuer           VARCHAR2(32);
            v_p_last_name                   VARCHAR2(32);
            v_p_first_name                  VARCHAR2(32);
            v_p_middle_name                 VARCHAR2(32); -- 30
            v_p_prefix                      VARCHAR2(32);
            v_p_suffix                      VARCHAR2(32);
            v_p_marital_status              CHAR(1);
            v_p_confidentiality             CHAR(1);
            v_p_patient_death_dttm          VARCHAR2(8);
            v_p_blood_type_rh               CHAR(1);
            v_p_citizenship                 VARCHAR2(32);
            v_p_occupation                  VARCHAR2(32);
            v_p_race_code                   VARCHAR2(32);
            v_p_language_code               VARCHAR2(32); -- 40
            v_p_religion_code               VARCHAR2(32);
            v_p_birth_place                 VARCHAR2(32);
            v_p_multiple_birth_status       VARCHAR2(32);
            v_p_birth_order                 VARCHAR2(32);
            v_p_cell_phone_no               VARCHAR2(40);
            v_p_pregnancy_code              VARCHAR2(32);
            v_p_patient_status              CHAR(1);
            v_p_account_number              VARCHAR2(32);
            v_p_contact_type                CHAR(3);
            v_p_business_phone_no           VARCHAR2(40); -- 50
            v_p_city                        VARCHAR2(32);
            v_p_state                       VARCHAR2(32);
            v_p_country                     VARCHAR2(64);
            v_p_visit_number                VARCHAR2(32);
            v_p_visit_status                CHAR(1);
            v_p_consult_doctor_id           VARCHAR2(64);
            v_p_institution_code            VARCHAR2(32);
            v_p_visit_comments              VARCHAR2(4000);
            v_p_admit_route                 CHAR(1);
            v_p_last_menstrual_dttm         VARCHAR2(14); -- 60
            v_p_code_abbreviation           VARCHAR2(32);
            v_p_station_code                VARCHAR2(32);
            v_p_consult_doctor_name         VARCHAR2(64);
            v_p_broker_type                 VARCHAR2(16); -- 64
        
        BEGIN
        
            sp_filter.patient_to_patient(
                    v_broker_aetitle,
                    v_event_type,
                    v_patient_id,
                    v_patient_name,
                    v_english_name,
                    v_patient_ssn,
                    v_patient_birth_dttm,
                    v_patient_sex,
                    v_patient_weight,
                    v_patient_size,        -- 10
                    v_ethnic_group,
                    v_tel_no,
                    v_fax_no,
                    v_zipcode,
                    v_address,
                    v_email,
                    v_blood_type,
                    v_pregnancy_status,
                    v_current_location,
                    v_current_residency,   -- 20
                    v_current_department,
                    v_current_doctor_id,
                    v_current_doctor_name,
                    v_admit_dttm,
                    v_discharge_dttm,
                    
                    v_p_prior_patient_id,
                    v_p_patient_id_issuer,
                    v_p_last_name,
                    v_p_first_name,
                    v_p_middle_name,           -- 30
                    v_p_prefix,
                    v_p_suffix,
                    v_p_marital_status,
                    v_p_confidentiality,
                    v_p_patient_death_dttm,
                    v_p_blood_type_rh,
                    v_p_citizenship,
                    v_p_occupation,
                    v_p_race_code,
                    v_p_language_code,      -- 40
                    v_p_religion_code,
                    v_p_birth_place,
                    v_p_multiple_birth_status,
                    v_p_birth_order,
                    v_p_cell_phone_no,
                    v_p_pregnancy_code,
                    v_p_patient_status,
                    v_p_account_number,
                    v_p_contact_type,
                    v_p_business_phone_no,    -- 50
                    v_p_city,
                    v_p_state,
                    v_p_country,
                    v_p_visit_number,
                    v_p_visit_status,
                    v_p_consult_doctor_id,
                    v_p_institution_code,
                    v_p_visit_comments,
                    v_p_admit_route,
                    v_p_last_menstrual_dttm,  -- 60
                    v_p_code_abbreviation,
                    v_p_station_code,
                    v_p_consult_doctor_name,
                    v_p_broker_type           -- 64
                );
            
            v_patient_key := sp_mapper.put_patient(
                    v_event_type,
                    v_patient_id                    ,
                    v_p_prior_patient_id            , -- v_prior_patient_id
                    v_p_patient_id_issuer           , -- v_patient_id_issuer_code
                    v_patient_ssn                   ,
                    v_patient_name                  ,
                    v_p_last_name                   , -- v_last_name
                    v_p_first_name                  , -- v_first_name
                    v_p_middle_name                 , -- v_middle_name
                    v_p_prefix                      , -- v_prefix                  -- 10
                    v_p_suffix                      , -- v_suffix
                    v_p_marital_status              , -- v_marital_stat
                    v_p_confidentiality             , -- v_confidentiality
                    v_patient_birth_dttm            ,
                    v_p_patient_death_dttm          , -- v_patient_death_dttm
                    v_patient_sex                   ,
                    v_patient_size                  ,
                    v_patient_weight                ,
                    v_blood_type                    ,
                    v_p_blood_type_rh               , -- v_blood_type_rh           -- 20
                    v_p_citizenship                 , -- v_citizenship
                    v_p_occupation                  , -- v_occupation
                    v_p_race_code                   , -- v_race_code
                    v_p_language_code               , -- v_language_code
                    v_p_religion_code               , -- v_religion_code
                    v_p_birth_place                 , -- v_birthplace
                    v_p_multiple_birth_status       , -- v_multiple_birth_status
                    v_p_birth_order                 , -- v_birth_order
                    v_email                         ,
                    v_p_cell_phone_no               , -- v_phone_no    -- 30
                    v_p_pregnancy_code              , -- v_pregnancy_code
                    v_p_patient_status              , -- v_patient_stat
                    v_p_account_number              , -- v_account_no
                    v_p_contact_type                , -- v_contact_type
                    v_tel_no                        , -- v_home_phone_no
                    v_p_business_phone_no           , -- v_busi_phone_no
                    v_fax_no                        ,
                    v_address                       ,
                    v_p_city                        , -- v_city
                    v_p_state                       , -- v_state -- 40
                    v_p_country                     , -- v_country
                    v_zipcode                       ,
                    v_p_visit_number                , -- v_visit_number
                    v_p_visit_status                , -- v_visit_stat
                    v_admit_dttm                    ,
                    v_discharge_dttm                ,
                    v_current_location              , -- v_patient_location
                    v_current_residency             , -- v_patient_residence
                    v_current_doctor_id             , -- v_refer_doctor_id
                    v_p_consult_doctor_id           , -- v_consult_doctor_id -- 50
                    v_p_institution_code            , -- v_institution_code    
                    v_p_visit_comments              , -- v_visit_comment
                    v_p_admit_route                 , -- v_admit_route
                    v_p_last_menstrual_dttm         , -- v_lastmen_strual_dttm
                    v_p_pregnancy_code              , -- v_pregnancy_status
                    v_p_code_abbreviation           , -- v_code_abbreviation
                    v_p_station_code                , -- v_station_code
                    v_english_name                  ,
                    v_ethnic_group                  ,
                    v_current_department            , -- 60
                    v_current_doctor_name           , -- v_refer_doctor_name
                    v_p_consult_doctor_name         , -- v_consult_doctor_name
                    v_broker_aetitle                ,
                    v_p_broker_type                   -- v_broker_type -- 64
                );
        END;


  DECLARE
    v_report_key NUMBER;
  BEGIN
    v_report_key := sp_mapper.put_report(
                        null, -- event_type
                        null, -- report_control_id
                        @EXAM_ID, -- accession_no
                        @PATIENT_ID, -- patient_id
                        @REPORT_STAT, -- report_stat
                        @CREATOR_ID, -- creator_id
                        @CREATOR_NAME, -- creator_name
                        @CREATE_DTTM, -- create_dttm
                        @DICTATOR_ID, -- dictator_id
                        @DICTATOR_NAME, -- dictator_name
                        @DICTATE_DTTM, -- dictate_dttm
                        @TRANSCRIBER_ID, -- transcriber_id
                        @TRANSCRIBER_NAME, -- transcriber_name
                        @TRANSCRIBE_DTTM, -- transcribe_dttm
                        @APPROVER_ID, -- approver_id
                        @APPROVER_NAME, -- approver_name
                        @APPROVE_DTTM, -- approve_dttm
                        @REVISER_ID, -- reviser_id
                        @REVISER_NAME, -- reviser_name
                        @REVISE_DTTM, -- revise_dttm
                        @REPORT_TYPE, -- report_type
                        $REPORT_TEXT, -- report_text  -- limit size : 32768
                        @CONCLUSION, -- conclusion
                        'ODBC' -- broker_type
                      );
  END;

      
        DECLARE
            v_report_key                    NUMBER;
            v_put_report_type               VARCHAR2(32)   := '';
            v_IsFirstReport                 VARCHAR2(32)   := '';

            v_broker_aetitle                VARCHAR2(32)   := '';
            v_flow_type                     NUMBER         := 0;
            v_patient_id                    VARCHAR2(64)   := @PATIENT_ID;
            v_exam_id                       VARCHAR2(32)   := @EXAM_ID;
            v_study_instance_uid            VARCHAR2(64)   := @STUDY_INSTANCE_UID;
            v_report_stat                   VARCHAR2(4)    := @REPORT_STAT;
            v_creator_id                    VARCHAR2(32)   := @CREATOR_ID;
            v_creator_name                  VARCHAR2(64)   := @CREATOR_NAME;
            v_create_dttm                   VARCHAR2(14)   := @CREATE_DTTM;
            v_dictator_id                   VARCHAR2(32)   := @DICTATOR_ID; -- 10
            v_dictator_name                 VARCHAR2(64)   := @DICTATOR_NAME;
            v_dictate_dttm                  VARCHAR2(14)   := @DICTATE_DTTM;
            v_transcriber_id                VARCHAR2(32)   := @TRANSCRIBER_ID;
            v_transcriber_name              VARCHAR2(64)   := @TRANSCRIBER_NAME;
            v_transcribe_dttm               VARCHAR2(14)   := @TRANSCRIBE_DTTM;
            v_approver_id                   VARCHAR2(32)   := @APPROVER_ID;
            v_approver_name                 VARCHAR2(64)   := @APPROVER_NAME;
            v_approve_dttm                  VARCHAR2(14)   := @APPROVE_DTTM;
            v_reviser_id                    VARCHAR2(32)   := @REVISER_ID;
            v_reviser_name                  VARCHAR2(64)   := @REVISER_NAME; -- 20
            v_revise_dttm                   VARCHAR2(14)   := @REVISE_DTTM;
            v_report_type                   VARCHAR2(32)   := @REPORT_TYPE;
            v_report_text                   LONG           := @REPORT_TEXT; -- limit size : 32768
            v_conclusion                    VARCHAR2(1024) := @CONCLUSION;
            v_study_dttm                    VARCHAR2(14)   := '';
            v_scheduled_location            VARCHAR2(32)   := '';
            v_perform_department            VARCHAR2(32)   := '';
            v_perform_modality              VARCHAR2(8)    := '';
            v_request_dttm                  VARCHAR2(14)   := '';
            v_request_name                  VARCHAR2(128)  := ''; -- 30
            v_request_code                  VARCHAR2(32)   := '';
            v_request_doctor                VARCHAR2(64)   := '';
            v_perform_doctor                VARCHAR2(64)   := '';
            v_refer_doctor                  VARCHAR2(64)   := '';
            v_scheduled_dttm                VARCHAR2(14)   := '';
            v_patient_name                  VARCHAR2(64)   := '';
            v_patient_sex                   CHAR(1)        := '';
            v_patient_birth_dttm            VARCHAR2(8)    := '';
            v_admission_id                  VARCHAR2(32)   := '';
            v_study_comments                VARCHAR2(4000) := ''; -- 40
            v_study_reason                  VARCHAR2(512)  := '';
            v_attend_doctor                 VARCHAR2(64)   := '';
            v_patient_location              VARCHAR2(32)   := '';
            v_scheduled_station             VARCHAR2(32)   := '';
            v_r_strFxCode                   VARCHAR2(32)   := '';
            v_r_strFxDesc                   VARCHAR2(1024) := '';
            v_r_strDxCode                   VARCHAR2(32)   := '';
            v_r_strDxDesc                   VARCHAR2(1024) := '';
            v_digital_sign_flag             CHAR(1)        := '';
            v_digital_sign_data             CLOB           := ''; -- 50
            v_digital_sign_dttm             VARCHAR2(14)   := '';
            v_certificate_dn                VARCHAR2(256)  := '';
            v_digital_sign_key              VARCHAR2(256)  := ''; -- 53
            
            v_r_event_type                  VARCHAR2(64);
            v_r_report_control_id           VARCHAR2(32);
            v_r_broker_type                 VARCHAR2(32);         -- 56

        BEGIN

            sp_filter.report_to_report(
                    v_broker_aetitle,
                    v_flow_type,
                    v_patient_id,
                    v_exam_id,
                    v_study_instance_uid,
                    v_report_stat,
                    v_creator_id,
                    v_creator_name,
                    v_create_dttm,
                    v_dictator_id,          -- 10
                    v_dictator_name,
                    v_dictate_dttm,
                    v_transcriber_id,
                    v_transcriber_name,
                    v_transcribe_dttm,
                    v_approver_id,
                    v_approver_name,
                    v_approve_dttm,
                    v_reviser_id,
                    v_reviser_name,         -- 20
                    v_revise_dttm,
                    v_report_type,
                    v_report_text,
                    v_conclusion,
                    v_study_dttm,
                    v_scheduled_location,
                    v_perform_department,
                    v_perform_modality,
                    v_request_dttm,
                    v_request_name,         -- 30
                    v_request_code,
                    v_request_doctor,
                    v_perform_doctor,
                    v_refer_doctor,
                    v_scheduled_dttm,
                    v_patient_name,
                    v_patient_sex,
                    v_patient_birth_dttm,
                    v_admission_id,
                    v_study_comments,       -- 40
                    v_study_reason,
                    v_attend_doctor,
                    v_patient_location,
                    v_scheduled_station,
                    v_r_strFxCode,
                    v_r_strFxDesc,
                    v_r_strDxCode,
                    v_r_strDxDesc,
                    v_digital_sign_flag,
                    v_digital_sign_data,    -- 50
                    v_digital_sign_dttm,
                    v_certificate_dn,
                    v_digital_sign_key,     -- 53
                    
                    v_r_event_type,
                    v_r_report_control_id,
                    v_r_broker_type         -- 56
                );
            
            v_report_key := sp_mapper.put_report(
                    v_r_event_type,         -- v_event_type
                    v_r_report_control_id , -- v_report_control_id
                    v_exam_id             , -- v_accession_no
                    v_patient_id          , 
                    v_report_stat         ,
                    v_creator_id          ,
                    v_creator_name        , 
                    v_create_dttm         , 
                    v_dictator_id         , 
                    v_dictator_name       , -- 10
                    v_dictate_dttm        , 
                    v_transcriber_id      , 
                    v_transcriber_name    , 
                    v_transcribe_dttm     ,
                    v_approver_id         , 
                    v_approver_name       ,
                    v_approve_dttm        ,
                    v_reviser_id          ,
                    v_reviser_name        ,
                    v_revise_dttm         , -- 20
                    v_report_type         , 
                    v_report_text         , 
                    v_conclusion          , 
                    v_r_broker_type       , -- v_broker_type
                    v_put_report_type     , 
                    v_IsFirstReport         -- 26
                );
        END;


  DECLARE
    v_user_key NUMBER;
  BEGIN
    v_user_key := sp_mapper.put_user(
                    @USER_ID, -- user_id
                    @USER_NAME, -- user_name
                    @PASSWORD, -- password
                    @USER_LEVEL, -- user_level
                    @USER_STATUS, -- user_status
                    @COMMENTS -- comments
                  );
  END;

      
        DECLARE
            v_user_key                      NUMBER;

            v_broker_aetitle                VARCHAR2(32)   := '';
            v_user_id                       VARCHAR2(64)   := @USER_ID;
            v_user_name                     VARCHAR2(64)   := @USER_NAME;
            v_password                      VARCHAR2(128)  := @PASSWORD;
            v_user_level                    VARCHAR2(16)   := @USER_LEVEL;
            v_user_status                   VARCHAR2(16)   := @USER_STATUS;
            v_comments                      VARCHAR2(2000) := @COMMENTS;

        BEGIN

            sp_filter.user_to_user(
                    v_broker_aetitle,
                    v_user_id,
                    v_user_name,
                    v_password,
                    v_user_level,
                    v_user_status,
                    v_comments
                );
            
            v_user_key := sp_mapper.put_user(
                    v_user_id,
                    v_user_name,
                    v_password, 
                    v_user_level,
                    v_user_status,
                    v_comments
                );
